import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Virtualized Scrolling List', () => {
  it('renders total count', () => {
    render(<App />);
    expect(screen.getByTestId('total-count')).toHaveTextContent('10000');
  });

  it('does NOT render all 10,000 rows', () => {
    render(<App />);
    // row-9999 should NOT be in the DOM if virtualization works
    expect(screen.queryByTestId('row-9999')).not.toBeInTheDocument();
  });

  it('renders first visible rows', () => {
    render(<App />);
    expect(screen.getByTestId('row-0')).toBeInTheDocument();
  });

  it('shows range display', () => {
    render(<App />);
    const range = screen.getByTestId('range-display');
    expect(range.textContent).toMatch(/Showing/);
  });

  it('scroll container has correct height', () => {
    render(<App />);
    const container = screen.getByTestId('scroll-container');
    expect(container.style.height).toBe('400px');
  });

  it('renders rows with absolute positioning', () => {
    render(<App />);
    const row = screen.getByTestId('row-0');
    expect(row.style.position).toBe('absolute');
  });

  it('inner spacer has total height', () => {
    render(<App />);
    const container = screen.getByTestId('scroll-container');
    const inner = container.firstElementChild as HTMLElement;
    expect(parseInt(inner.style.height)).toBe(400000);
  });
});

