import React, { useState, useRef, useCallback } from 'react';
import './styles.css';

interface Item {
  id: number;
  label: string;
}

interface VirtualListProps {
  items: Item[];
  rowHeight: number;
  containerHeight: number;
  overscan: number;
}

export const VirtualList: React.FC<VirtualListProps> = ({
  items,
  rowHeight,
  containerHeight,
  overscan,
}) => {
  const [scrollTop, setScrollTop] = useState(0);

  const totalHeight = items.length * rowHeight;
  const startIndex = Math.max(0, Math.floor(scrollTop / rowHeight) - overscan);
  const visibleCount = Math.ceil(containerHeight / rowHeight);
  const endIndex = Math.min(items.length - 1, startIndex + visibleCount + overscan * 2);

  const visibleItems = [];
  for (let i = startIndex; i <= endIndex; i++) {
    visibleItems.push({ item: items[i], index: i });
  }

  const displayStart = Math.floor(scrollTop / rowHeight) + 1;
  const displayEnd = Math.min(displayStart + visibleCount - 1, items.length);

  const handleScroll = useCallback((e: React.UIEvent<HTMLDivElement>) => {
    setScrollTop(e.currentTarget.scrollTop);
  }, []);

  return (
    <div>
      <p data-testid="total-count" className="vlist__meta">
        Total: {items.length} items
      </p>
      <p data-testid="range-display" className="vlist__meta">
        Showing {displayStart}–{displayEnd} of {items.length}
      </p>

      <div
        data-testid="scroll-container"
        className="vlist__container"
        style={{ height: containerHeight }}
        onScroll={handleScroll}
      >
        <div className="vlist__inner" style={{ height: totalHeight }}>
          {visibleItems.map(({ item, index }) => (
            <div
              key={item.id}
              data-testid={`row-${index}`}
              className="vlist__row"
              style={{
                height: rowHeight,
                position: 'absolute',
                top: index * rowHeight,
              }}
            >
              <span className="vlist__index">{index + 1}</span>
              <span>{item.label}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};
